// reader(data) - creates a stateful binary reader
// Auto-advances position after each read

const r = reader(input);

// Read integers
const cmd = r.uint8();        // 1 byte
const id = r.uint16LE();      // 2 bytes, little-endian
const flags = r.uint32LE();   // 4 bytes, little-endian

// Big-endian variants: r.uint16BE(), r.uint32BE()
// Signed variants: r.int8(), r.int16LE(), r.int32LE()
// Variable length: r.uintLE(n), r.intBE(n) - returns bigint if n > 4

// Read raw bytes
const payload = r.bytes(4);  // next 4 bytes as Uint8Array

// Utility methods
// r.skip(n)      - skip n bytes
// r.pos         - current position (read/write)
// r.remaining() - bytes left to read

ctx.log(`cmd=${cmd} id=${id} flags=${flags}`);
return payload;

// writer() - creates a chainable binary builder

const w = writer();

// Write integers
w.uint8(0x01);             // 1 byte
w.uint16LE(0x1234);        // 2 bytes -> [0x34, 0x12]
w.uint32LE(0xDEADBEEF);    // 4 bytes -> [0xEF, 0xBE, 0xAD, 0xDE]

// Big-endian variants: w.uint16BE(), w.uint32BE()
// Signed variants: w.int8(), w.int16LE(), w.int32LE()
// Variable length: w.uintLE(value, n), w.intBE(value, n)

// Write raw bytes
w.bytes([0xAA, 0xBB]);
w.bytes(input);  // append input buffer

// Chaining supported
// writer().uint8(1).uint16LE(2).uint32LE(3).build()

return w.build();  // returns Uint8Array

// Variables persist across function calls
// Must be declared in Variables tab first

// Read a variable
const count = ctx.getVar('counter');

// Write a variable (type must match)
ctx.setVar('counter', count + 1);

// Variable types:
// - u8, u16, u32: numbers
// - hex: Uint8Array
// - string: text

// Logging
ctx.log('Counter: ' + (count + 1));
console.log('Also works:', count + 1);
// console.warn(), console.error(), console.info()

// Return counter as little-endian u32
return writer().uint32LE(count + 1).build();

// Example: parse request, build response
// Request:  [cmd:uint8] [len:uint8] [data:len bytes]
// Response: [status:uint8] [cmd:uint8] [result:uint16]

const r = reader(input);
const cmd = r.uint8();
const len = r.uint8();
const data = r.bytes(len);

// Process data (sum all bytes)
let sum = 0;
for (const b of data) sum += b;

ctx.log(`cmd=${cmd} len=${len} sum=${sum}`);

// Build response
return writer()
  .uint8(0x00)      // status: OK
  .uint8(cmd)       // echo command
  .uint16LE(sum)    // result
  .build();
